import request from '@/utils/request'
import { SMS_SCENE } from '@/store'

export const auth = {
  // 密码登录
  login: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/auth/login/password/',
        method: 'post',
        headers: {
          'Content-Type': 'application/json'
        },
        data: {
          phone: data.phone.trim(),
          password: data.password
        }
      })

      return response
    } catch (error) {
      console.error('Login Error:', error)
      console.error('Error Response:', error.response?.data)

      if (error.response?.data?.non_field_errors?.length > 0) {
        const errorMessage = error.response.data.non_field_errors[0]
        if (errorMessage.includes('不存在')) {
          error.code = 'user_not_found'
        } else if (errorMessage.includes('密码错误')) {
          error.code = 'invalid_password'
        }
        error.message = errorMessage
      }
      throw error
    }
  },

  // 退出登录
  logout: () => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      console.warn('No token found for logout')
      return Promise.resolve()
    }

    return request({
      url: '/api/v1/users/auth/logout/',
      method: 'post',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': 'application/json',
        'Content-Type': 'application/json'
      }
    }).catch(error => {
      if (error.response?.status === 401) {
        console.warn('Token already expired during logout')
        return Promise.resolve()
      }
      throw error
    })
  },

  // 刷新 token
  refreshToken: (data) => {
    return request({
      url: '/api/v1/users/auth/token/refresh/',
      method: 'post',
      data
    })
  },

  // 注册
  register: (data) => {
    return request({
      url: '/api/v1/users/auth/register/',
      method: 'post',
      data: {
        phone: data.phone,
        code: data.code,
        password: data.password
      }
    })
  },

  // 发送验证码
  sendVerifyCode: async (data) => {
    try {
      const config = {
        url: '/api/v1/users/auth/sms/send/',
        method: 'post',
        headers: {
          'Content-Type': 'application/json'
        },
        data: {
          phone: data.phone.trim(),
          scene: data.scene,
          // 添加可选的登录模式
          login_mode: data.login_mode || 'password'
        }
      }

      // 如果是修改手机号场景，需要添加 token
      if (data.scene === SMS_SCENE.CHANGE_PHONE) {
        const token = localStorage.getItem('access_token')
        if (!token) {
          throw new Error('未登录或登录已过期')
        }
        config.headers['Authorization'] = `Bearer ${token}`
      }

      console.log('Sending verify code request:', {
        ...config,
        headers: {
          ...config.headers,
          Authorization: config.headers.Authorization ? 
            `Bearer ${config.headers.Authorization.substring(0, 10)}...` : 
            undefined
        }
      })

      const response = await request(config)
      console.log('Verify code response:', response)
      return response
    } catch (error) {
      console.error('Send Code Error:', error)
      console.error('Error details:', {
        status: error.response?.status,
        data: error.response?.data,
        headers: error.response?.headers,
        config: {
          ...error.config,
          headers: {
            ...error.config?.headers,
            Authorization: error.config?.headers?.Authorization ? 
              'Bearer ***' : undefined
          }
        }
      })

      if (error.response?.status === 500) {
        throw new Error('服务器错误，请稍后重试')
      }

      if (error.response?.status === 401) {
        throw new Error('登录已过期，请重新登录')
      }

      if (error.response?.status === 400) {
        const errorData = error.response?.data
        const errorMsg = errorData?.message 
          || errorData?.detail
          || errorData?.phone?.[0]
          || errorData?.errors?.phone?.[0]
          || errorData?.errors?.scene?.[0]
          || '发送验证码失败'
        throw new Error(errorMsg)
      }

      throw error
    }
  },

  // 重置密码
  resetPassword: (data) => {
    return request({
      url: '/api/v1/users/auth/password/reset/',
      method: 'post',
      data: {
        phone: data.phone.trim(),
        code: data.code,
        new_password: data.new_password,
        confirm_password: data.confirm_password
      }
    })
  },

  // 更换手机号
  changePhone: (data) => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      throw new Error('未登录或登录已过期')
    }

    // 打印请求数据
    console.log('Change phone request data:', {
      new_phone: data.phone.trim(),
      code: data.code
    })

    return request({
      url: '/api/v1/users/account/phone/',
      method: 'post',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      data: {
        new_phone: data.phone.trim(),
        code: data.code
      }
    }).catch(error => {
      // 打印详细的错误信息
      console.error('Change phone error details:', {
        status: error.response?.status,
        data: error.response?.data,
        headers: error.response?.headers,
        config: error.config
      })

      if (error.response?.status === 400) {
        const errorData = error.response?.data
        console.log('Error response data:', errorData)

        // 尝试获取所有可能的错误信息
        const errorMsg = errorData?.errors?.new_phone?.[0]  // 先检查 errors 字段
          || errorData?.errors?.code?.[0]
          || errorData?.message  // 然后检查顶层 message
          || errorData?.detail
          || (typeof errorData === 'string' ? errorData : null)
          || '更换手机号失败'

        // 如果是手机号已存在的错误，给出更明确的提示
        if (errorMsg.includes('已存在') || errorMsg.includes('已被使用')) {
          throw new Error('该手机号已被其他账号使用')
        }

        // 如果是验证码错误，给出更明确的提示
        if (errorMsg.includes('验证码')) {
          throw new Error('验证码错误或已过期')
        }

        throw new Error(errorMsg)
      }
      throw error
    })
  }
}
